#include<bits/stdc++.h>
using namespace std;
#define ll long long
#define dbg(x) cerr<<#x" = "<<(x)<<'\n';
const int N=10005;
int n,m,k,s,t;
struct node
{
	int v,w;
};
vector<node> g[N];
struct Node
{
	int x,y,z; // x:pos  y:k  z:dis
	bool operator<(const Node other) const
	{
		return z>other.z;
	}
};
int ans[N][15],vis[N][15];
void dij()
{
	memset(ans,0x3f,sizeof(ans));
	priority_queue<Node> pq;
	ans[s][0]=0;
	pq.push(Node{s,0,0});
	while(!pq.empty())
	{
		Node t=pq.top();
		pq.pop();
		int u=t.x,tt=t.y;
//		cout<<u<<"  k: "<<tt<<"  "<<t.z<<":\n";
		if(vis[u][tt]) continue;
		vis[u][tt]=1;
		for(int i=0;i<g[u].size();i++)
		{
			int v=g[u][i].v,w=g[u][i].w;
//			cout<<v<<"  , "<<w<<"\n";
			if(!vis[v][tt]&&ans[u][tt]+w<ans[v][tt])
			{ 
				ans[v][tt]=ans[u][tt]+w;
				pq.push(Node{v,tt,ans[v][tt]});
			}
			if(tt!=k)
			{
				if(!vis[v][tt+1]&&ans[u][tt]<ans[v][tt+1])
				{
					ans[v][tt+1]=ans[u][tt];
					pq.push(Node{v,tt+1,ans[v][tt+1]});
				}
			}
		}
	}
}
int main()
{
	cin>>n>>m>>k>>s>>t;
	for(int i=1;i<=m;i++)
	{
		int a,b,c;
		cin>>a>>b>>c;
		g[a].push_back(node{b,c});
		g[b].push_back(node{a,c});
	}
	dij();
	int anss=0x3f3f3f3f;
	for(int i=0;i<=k;i++) anss=min(anss,ans[t][i]);
	cout<<anss;
	return 0;
}
